#include <bits/stdc++.h>
using namespace std;
long long n,p,z[101],a[101],b[101];

bool check(long long m){
    long long sum=0;
    for(long long i=1;i<=n;i++){
        if(m<=z[i])sum+=m*a[i];
        else sum+=a[i]*z[i]+(m-z[i])*b[i];
    }
    return sum>=p;
}

int main(){
    cin>>n>>p;
    for(long long i=1;i<=n;i++)cin>>z[i]>>a[i]>>b[i];
    long long l=1,r=p,ans=0;
    while(l<=r){
        long long mid=(l+r)/2;
        if(check(mid)){
            r=mid-1;
            ans=mid;
        }else l=mid+1;
    }
    cout<<ans;
    return 0;
}
